import { useMemo } from 'react';

const C = {
  bg: '#0B0F14',
  surface: '#0F1620',
  border: '#1F2A37',
  text: '#E5E7DB',
  muted: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
  amber: '#F59E0B',
  purple: '#A78BFA',
};
const font = "'JetBrains Mono', monospace";

function generateMockData(numBars = 15, levelsPerBar = 8) {
  const bars = [];
  let price = 4500;
  for (let b = 0; b < numBars; b++) {
    price += (Math.random() - 0.48) * 12;
    const levels = [];
    const basePrice = price;
    for (let l = 0; l < levelsPerBar; l++) {
      const levelPrice = basePrice + (l - levelsPerBar / 2) * 2;
      const buyVol = Math.floor(Math.random() * 800 + 50);
      const sellVol = Math.floor(Math.random() * 800 + 50);
      levels.push({ price: levelPrice.toFixed(2), buyVol, sellVol });
    }
    levels.sort((a, b) => parseFloat(b.price) - parseFloat(a.price));
    bars.push({ levels, closePrice: price.toFixed(2) });
  }
  return bars;
}

export default function FootprintChart() {
  const bars = useMemo(() => generateMockData(15, 8), []);

  const CELL_W = 54;
  const CELL_H = 22;
  const LEVELS = bars[0].levels.length;
  const BARS = bars.length;
  const PRICE_AXIS_W = 64;
  const PROFILE_W = 60;
  const DELTA_H = 28;
  const PADDING_TOP = 24;
  const PADDING_LEFT = 8;

  const maxVol = useMemo(() => {
    let m = 0;
    bars.forEach(b => b.levels.forEach(l => { if (l.buyVol > m) m = l.buyVol; if (l.sellVol > m) m = l.sellVol; }));
    return m;
  }, [bars]);

  const totalWidth = PADDING_LEFT + BARS * CELL_W + PRICE_AXIS_W + PROFILE_W + 8;
  const totalHeight = PADDING_TOP + LEVELS * CELL_H + DELTA_H + 8;

  // Volume profile: sum all buy+sell per price level index
  const profileTotals = useMemo(() => {
    return Array.from({ length: LEVELS }, (_, li) => {
      return bars.reduce((sum, b) => sum + (b.levels[li]?.buyVol || 0) + (b.levels[li]?.sellVol || 0), 0);
    });
  }, [bars, LEVELS]);
  const maxProfile = Math.max(...profileTotals);

  return (
    <div style={{ background: C.bg, padding: 20, borderRadius: 14, fontFamily: font, display: 'inline-block' }}>
      <div style={{ marginBottom: 12 }}>
        <span style={{ fontSize: 14, fontWeight: 700, color: C.text }}>Volume Footprint</span>
        <span style={{ fontSize: 11, color: C.muted, marginLeft: 12 }}>Buy (green) / Sell (red) per price level</span>
      </div>
      <div style={{ overflowX: 'auto' }}>
        <svg width={totalWidth} height={totalHeight} style={{ display: 'block' }}>
          {/* Column headers */}
          {bars.map((bar, bi) => (
            <text
              key={bi}
              x={PADDING_LEFT + bi * CELL_W + CELL_W / 2}
              y={14}
              textAnchor="middle"
              fill={C.muted}
              fontSize={9}
              fontFamily={font}
            >
              {bi + 1}
            </text>
          ))}

          {/* Cells */}
          {bars.map((bar, bi) =>
            bar.levels.map((level, li) => {
              const x = PADDING_LEFT + bi * CELL_W;
              const y = PADDING_TOP + li * CELL_H;
              const buyW = Math.round((level.buyVol / maxVol) * (CELL_W / 2 - 2));
              const sellW = Math.round((level.sellVol / maxVol) * (CELL_W / 2 - 2));
              const delta = level.buyVol - level.sellVol;
              const isPosDelta = delta >= 0;

              return (
                <g key={`${bi}-${li}`}>
                  {/* Cell background */}
                  <rect
                    x={x + 1}
                    y={y + 1}
                    width={CELL_W - 2}
                    height={CELL_H - 2}
                    fill={C.surface}
                    stroke={C.border}
                    strokeWidth={0.5}
                    rx={1}
                  />
                  {/* Buy vol bar (left half, grows right from center) */}
                  <rect
                    x={x + CELL_W / 2 - buyW}
                    y={y + 3}
                    width={buyW}
                    height={CELL_H - 6}
                    fill={C.green + 'AA'}
                    rx={1}
                  />
                  {/* Sell vol bar (right half, grows left from center) */}
                  <rect
                    x={x + CELL_W / 2}
                    y={y + 3}
                    width={sellW}
                    height={CELL_H - 6}
                    fill={C.red + 'AA'}
                    rx={1}
                  />
                  {/* Delta text */}
                  <text
                    x={x + CELL_W / 2}
                    y={y + CELL_H / 2 + 4}
                    textAnchor="middle"
                    fill={isPosDelta ? C.green : C.red}
                    fontSize={8}
                    fontFamily={font}
                    fontWeight={700}
                  >
                    {isPosDelta ? '+' : ''}{delta}
                  </text>
                </g>
              );
            })
          )}

          {/* Price axis */}
          {bars[0].levels.map((level, li) => {
            const y = PADDING_TOP + li * CELL_H;
            return (
              <text
                key={li}
                x={PADDING_LEFT + BARS * CELL_W + 6}
                y={y + CELL_H / 2 + 4}
                fill={C.muted}
                fontSize={9}
                fontFamily={font}
              >
                {parseFloat(level.price).toFixed(0)}
              </text>
            );
          })}

          {/* Volume profile bars */}
          {profileTotals.map((total, li) => {
            const y = PADDING_TOP + li * CELL_H;
            const profileBarW = Math.round((total / maxProfile) * (PROFILE_W - 8));
            return (
              <g key={li}>
                <rect
                  x={PADDING_LEFT + BARS * CELL_W + PRICE_AXIS_W}
                  y={y + 3}
                  width={profileBarW}
                  height={CELL_H - 6}
                  fill={C.blue + '66'}
                  rx={1}
                />
              </g>
            );
          })}

          {/* Profile label */}
          <text
            x={PADDING_LEFT + BARS * CELL_W + PRICE_AXIS_W + PROFILE_W / 2 - 10}
            y={14}
            fill={C.blue}
            fontSize={9}
            fontFamily={font}
          >
            Profile
          </text>

          {/* Delta row */}
          {bars.map((bar, bi) => {
            const totalBuy = bar.levels.reduce((s, l) => s + l.buyVol, 0);
            const totalSell = bar.levels.reduce((s, l) => s + l.sellVol, 0);
            const delta = totalBuy - totalSell;
            const x = PADDING_LEFT + bi * CELL_W;
            const y = PADDING_TOP + LEVELS * CELL_H + 6;
            return (
              <g key={bi}>
                <rect
                  x={x + 1}
                  y={y}
                  width={CELL_W - 2}
                  height={DELTA_H - 4}
                  fill={delta >= 0 ? C.green + '22' : C.red + '22'}
                  stroke={delta >= 0 ? C.green + '55' : C.red + '55'}
                  strokeWidth={0.5}
                  rx={2}
                />
                <text
                  x={x + CELL_W / 2}
                  y={y + DELTA_H / 2 + 2}
                  textAnchor="middle"
                  fill={delta >= 0 ? C.green : C.red}
                  fontSize={8}
                  fontFamily={font}
                  fontWeight={700}
                >
                  {delta >= 0 ? '+' : ''}{delta}
                </text>
              </g>
            );
          })}
          {/* Delta label */}
          <text
            x={PADDING_LEFT + BARS * CELL_W + 6}
            y={PADDING_TOP + LEVELS * CELL_H + DELTA_H / 2 + 2}
            fill={C.amber}
            fontSize={9}
            fontFamily={font}
          >
            Δ
          </text>
        </svg>
      </div>
      {/* Legend */}
      <div style={{ display: 'flex', gap: 16, marginTop: 8 }}>
        {[{ color: C.green, label: 'Buy Volume' }, { color: C.red, label: 'Sell Volume' }, { color: C.blue, label: 'Profile' }, { color: C.amber, label: 'Bar Delta' }].map(({ color, label }) => (
          <div key={label} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <div style={{ width: 10, height: 10, background: color, borderRadius: 6 }} />
            <span style={{ fontSize: 10, color: C.muted }}>{label}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
